@import "tailwindcss";
@import "@fontsource/shippori-mincho/400.css";
@import "@fontsource/shippori-mincho/500.css";
@import "@fontsource/shippori-mincho/700.css";

/* テーマカラー - ライトモード */
:root {
	--primary-color: #4f46e5;
	--bg-primary: #ffffff;
	--bg-secondary: #f8fafc;
	--bg-tertiary: #f1f5f9;
	--text-primary: #1a1a1a;
	--text-secondary: #4b5563;
	--text-muted: #9ca3af;
	--border-color: #e2e8f0;
	--link-color: #2563eb;
	--link-hover-color: #1d4ed8;
	--blockquote-bg: #eff6ff;
	--blockquote-border: #3b82f6;
	--code-bg: #f1f5f9;
	--code-text: #1e293b;
}

/* テーマカラー - ダークモード */
:root.dark {
	--primary-color: #818cf8;
	--bg-primary: #0f172a;
	--bg-secondary: #1e293b;
	--bg-tertiary: #334155;
	--text-primary: #f1f5f9;
	--text-secondary: #cbd5e1;
	--text-muted: #64748b;
	--border-color: #334155;
	--link-color: #60a5fa;
	--link-hover-color: #93c5fd;
	--blockquote-bg: #1e3a5f;
	--blockquote-border: #3b82f6;
	--code-bg: #1e293b;
	--code-text: #e2e8f0;
}

/* フォーカス表示の強化 */
:focus-visible {
	outline: 2px solid var(--primary-color);
	outline-offset: 2px;
}

/* デフォルトのoutlineを消してfocus-visibleで制御 */
:focus:not(:focus-visible) {
	outline: none;
}

/* Code block styles */
.prose pre {
	position: relative;
	padding: 1rem;
	border-radius: 0.5rem;
	overflow-x: auto;
}

.prose pre code {
	font-family: "SF Mono", Menlo, Monaco, "Courier New", monospace;
	font-size: 0.875rem;
	line-height: 1.6;
}

/* Code block copy button */
.prose pre .copy-button {
	position: absolute;
	top: 0.5rem;
	right: 0.5rem;
	padding: 0.375rem;
	background: rgba(255, 255, 255, 0.1);
	border: none;
	border-radius: 0.375rem;
	cursor: pointer;
	opacity: 0;
	transition: opacity 0.2s;
}

.prose pre:hover .copy-button {
	opacity: 1;
}

.prose pre .copy-button:hover {
	background: rgba(255, 255, 255, 0.2);
}

.prose pre .copy-button svg {
	width: 1rem;
	height: 1rem;
	color: #a0aec0;
}

.prose pre .copy-button.copied svg {
	color: #48bb78;
}

/* Inline code */
.prose :not(pre) > code {
	background: var(--code-bg);
	padding: 0.125rem 0.375rem;
	border-radius: 0.25rem;
	font-size: 0.875em;
	font-weight: 500;
	color: var(--code-text);
}

/* Better heading anchors */
.prose h2,
.prose h3,
.prose h4 {
	scroll-margin-top: 4rem;
}

/* Blockquote styling */
.prose blockquote {
	border-left-color: var(--blockquote-border);
	background: var(--blockquote-bg);
	padding: 1rem;
	border-radius: 0 0.5rem 0.5rem 0;
	font-style: normal;
}

.prose blockquote p {
	margin: 0;
}

/* Table styling */
.prose table {
	width: 100%;
	border-collapse: collapse;
}

.prose th {
	background: var(--bg-secondary);
	font-weight: 600;
}

.prose th,
.prose td {
	border: 1px solid var(--border-color);
	padding: 0.75rem;
}

.prose tr:hover {
	background: var(--bg-secondary);
}

/* Task list styling */
.prose ul:has(input[type="checkbox"]) {
	list-style: none;
	padding-left: 0;
}

.prose li:has(> input[type="checkbox"]) {
	display: flex;
	align-items: flex-start;
	gap: 0.5rem;
}

.prose input[type="checkbox"] {
	margin-top: 0.375rem;
	accent-color: #3b82f6;
}

/* Image styling */
.prose img {
	border-radius: 0.5rem;
	box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1);
}

/* Link styling */
.prose a {
	color: var(--link-color);
	text-decoration: underline;
	text-underline-offset: 2px;
}

.prose a:hover {
	color: var(--link-hover-color);
}

/* Reduced motion preference */
@media (prefers-reduced-motion: reduce) {
	*,
	*::before,
	*::after {
		animation-duration: 0.01ms !important;
		animation-iteration-count: 1 !important;
		transition-duration: 0.01ms !important;
		scroll-behavior: auto !important;
	}
}

