 1→---
 2→// ヒーローセクション - Three.js背景付き
 3→import Button from "../ui/Button.astro";
 4→import ThreeBackground from "./ThreeBackground.astro";
 5→---
 6→
 7→<section id="hero" class="hero-section">
 8→  <ThreeBackground />
 9→
10→  <div class="hero-content">
11→    <div class="hero-greeting" data-animate="fade-up">
12→      <span>Welcome to my portfolio</span>
13→    </div>
14→
15→    <h1 class="hero-title" data-animate="fade-up">
16→      <span class="hero-name">ta93abe</span>
17→    </h1>
18→
19→    <p class="hero-description" data-animate="fade-up">
20→      Software Engineer & Creative Developer
21→    </p>
22→
23→    <div class="hero-cta" data-animate="fade-up">
24→      <Button href="/works" variant="primary" size="lg">View Works</Button>
25→      <Button href="/links" variant="secondary" size="lg">Links</Button>
26→    </div>
27→  </div>
28→</section>
29→
30→<style>
31→  .hero-section {
32→    position: relative;
33→    min-height: 100dvh;
34→    display: flex;
35→    align-items: center;
36→    justify-content: center;
37→    overflow: hidden;
38→    background: #fafafa;
39→  }
40→
41→  .hero-content {
42→    position: relative;
43→    z-index: 10;
44→    text-align: center;
45→    padding: 2rem;
46→  }
47→
48→  .hero-greeting {
49→    margin-bottom: 1rem;
50→  }
51→
52→  .hero-greeting span {
53→    display: inline-block;
54→    font-size: 0.875rem;
55→    text-transform: uppercase;
56→    color: #666;
