---
// ヒーローセクション - Three.js背景付き
import Button from "../ui/Button.astro";
import ThreeBackground from "./ThreeBackground.astro";
---

<section id="hero" class="hero-section">
  <ThreeBackground />

  <div class="hero-content">
    <div class="hero-greeting" data-animate="fade-up">
      <span>Welcome to my portfolio</span>
    </div>

    <h1 class="hero-title" data-animate="fade-up">
      <span class="hero-name">ta93abe</span>
    </h1>

    <p class="hero-description" data-animate="fade-up">
      Software Engineer & Creative Developer
    </p>

    <div class="hero-cta" data-animate="fade-up">
      <Button href="/works" variant="primary" size="lg">View Works</Button>
      <Button href="/links" variant="secondary" size="lg">Links</Button>
    </div>
  </div>
</section>

<style>
  .hero-section {
    position: relative;
    min-height: 100dvh;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    background: #fafafa;
  }

  .hero-content {
    position: relative;
    z-index: 10;
    text-align: center;
    padding: 2rem;
  }

  .hero-greeting {
    margin-bottom: 1rem;
  }

  .hero-greeting span {
    display: inline-block;
    font-size: 0.875rem;
    text-transform: uppercase;
    color: #666;
  }

  .hero-title {
    font-size: clamp(4rem, 18vw, 12rem);
    font-weight: 700;
    line-height: 1;
    margin: 0;
    color: #1a1a1a;
  }

  .hero-name {
    display: inline-block;
    color: #1a1a1a;
  }

  .hero-description {
    font-size: clamp(1.125rem, 2.5vw, 1.5rem);
    color: #555;
    margin: 1.5rem 0 2.5rem;
    font-weight: 400;
  }

  .hero-cta {
    display: flex;
    gap: 1rem;
    justify-content: center;
    flex-wrap: wrap;
  }

  @media (max-width: 768px) {
    .hero-section {
      min-height: 100svh;
    }
  }
</style>

