290→<script>
291→  function initEnsCard() {
292→    const card = document.querySelector<HTMLElement>("[data-ens-card]");
293→    if (!card || card.dataset.ensCardInitialized) return;
294→    card.dataset.ensCardInitialized = "true";
295→
296→    const prefersReducedMotion = window.matchMedia(
297→      "(prefers-reduced-motion: reduce)",
298→    );
299→    if (prefersReducedMotion.matches) return;
300→
301→    const shine = document.querySelector<HTMLElement>("[data-ens-shine]");
302→    if (!shine) return;
303→
304→    const MAX_ROTATION = 15;
305→    const NEUTRAL_BETA = 45;
306→    const BETA_SENSITIVITY_RANGE = 45;
307→
308→    function handleMouseMove(e: MouseEvent) {
309→      const rect = card!.getBoundingClientRect();
310→      const centerX = rect.left + rect.width / 2;
311→      const centerY = rect.top + rect.height / 2;
312→
313→      const mouseX = e.clientX - centerX;
314→      const mouseY = e.clientY - centerY;
315→
316→      const rotateY = (mouseX / (rect.width / 2)) * MAX_ROTATION;
317→      const rotateX = -(mouseY / (rect.height / 2)) * MAX_ROTATION;
318→
319→      card!.style.transform = `rotateX(${rotateX}deg) rotateY(${rotateY}deg)`;
320→
321→      const shineX = ((e.clientX - rect.left) / rect.width) * 100;
322→      const shineY = ((e.clientY - rect.top) / rect.height) * 100;
323→      shine!.style.background = `radial-gradient(
324→        circle at ${shineX}% ${shineY}%,
325→        rgba(255, 219, 112, 0.25) 0%,
326→        rgba(132, 50, 255, 0.12) 30%,
327→        transparent 60%
328→      )`;
329→      shine!.style.opacity = "1";
330→    }
331→
332→    function handleMouseLeave() {
333→      card!.style.transition = "transform 0.5s ease-out";
334→      card!.style.transform = "rotateX(0deg) rotateY(0deg)";
335→      shine!.style.opacity = "0";
336→
337→      setTimeout(() => {
338→        card!.style.transition = "transform 0.1s ease-out";
339→      }, 500);
340→    }
341→
342→    card.addEventListener("mousemove", handleMouseMove);
343→    card.addEventListener("mouseleave", handleMouseLeave);
344→
345→    // Mobile: DeviceOrientation for gyro-based tilt
346→    function handleOrientation(e: DeviceOrientationEvent) {
347→      if (e.gamma === null || e.beta === null) return;
348→
349→      const rotateY = (e.gamma / 90) * MAX_ROTATION;
350→      const rotateX = Math.max(
351→        -MAX_ROTATION,
352→        Math.min(
353→          MAX_ROTATION,
354→          ((e.beta - NEUTRAL_BETA) / BETA_SENSITIVITY_RANGE) * MAX_ROTATION,
355→        ),
356→      );
357→
358→      card!.style.transform = `rotateX(${rotateX}deg) rotateY(${rotateY}deg)`;
359→      shine!.style.opacity = "0.6";
360→    }
361→
362→    // Only add gyro on touch devices
363→    if ("ontouchstart" in window) {
364→      if (
365→        typeof DeviceOrientationEvent !== "undefined" &&
366→        typeof (DeviceOrientationEvent as any).requestPermission === "function"
367→      ) {
368→        card.addEventListener(
369→          "click",
370→          () => {
371→            (DeviceOrientationEvent as any)
372→              .requestPermission()
373→              .then((response: string) => {
374→                if (response === "granted") {
375→                  window.addEventListener(
376→                    "deviceorientation",
377→                    handleOrientation,
378→                  );
379→                }
380→              })
381→              .catch(() => {});
382→          },
383→          { once: true },
384→        );
385→      } else if (typeof DeviceOrientationEvent !== "undefined") {
386→        window.addEventListener("deviceorientation", handleOrientation);
387→      }
388→    }
389→
390→    // Listen for reduced motion changes
391→    const handleReducedMotionChange = (e: MediaQueryListEvent) => {
392→      if (e.matches) {
393→        card!.style.transform = "";
394→        shine!.style.opacity = "0";
395→        card!.removeEventListener("mousemove", handleMouseMove);
396→        card!.removeEventListener("mouseleave", handleMouseLeave);
397→        window.removeEventListener("deviceorientation", handleOrientation);
398→        prefersReducedMotion.removeEventListener(
399→          "change",
400→          handleReducedMotionChange,
401→        );
402→      }
403→    };
404→    prefersReducedMotion.addEventListener("change", handleReducedMotionChange);
405→
406→    // Cleanup on Astro page swap to prevent memory leaks
407→    document.addEventListener(
408→      "astro:before-swap",
409→      () => {
410→        card!.removeEventListener("mousemove", handleMouseMove);
411→        card!.removeEventListener("mouseleave", handleMouseLeave);
412→        window.removeEventListener("deviceorientation", handleOrientation);
413→        prefersReducedMotion.removeEventListener(
414→          "change",
415→          handleReducedMotionChange,
416→        );
417→      },
418→      { once: true },
419→    );
420→  }
421→
422→  document.addEventListener("astro:page-load", initEnsCard);
423→</script>
