                <circle cx="12" cy="12" r="10" />
                <path d="M2 12h20" />
                <path d="M12 2a15.3 15.3 0 014 10 15.3 15.3 0 01-4 10 15.3 15.3 0 01-4-10 15.3 15.3 0 014-10z" />
              </svg>
            </a>
          )}
        </div>
      )}
    </div>
  </div>
</div>

<style>
  .ens-card-wrapper {
    perspective: 1000px;
    width: 100%;
    max-width: 360px;
    margin: 0 auto;
  }

  .ens-card {
    position: relative;
    transform-style: preserve-3d;
    transition: transform 0.1s ease-out;
    border-radius: 1.25rem;
    background: #1a1a2e;
    border: 1px solid rgba(255, 255, 255, 0.08);
    box-shadow:
      0 4px 24px rgba(0, 0, 0, 0.12),
      0 0 0 1px rgba(255, 255, 255, 0.04);
    overflow: hidden;
    will-change: transform;
  }

  .ens-card-shine {
    position: absolute;
    inset: 0;
    z-index: 1;
    pointer-events: none;
    border-radius: inherit;
    background: linear-gradient(
      105deg,
      transparent 40%,
      rgba(255, 219, 112, 0.2) 45%,
      rgba(132, 50, 255, 0.1) 50%,
      transparent 54%
    );
    opacity: 0;
    transition: opacity 0.3s ease;
    mix-blend-mode: screen;
  }

  .ens-card:hover .ens-card-shine {
    opacity: 1;
  }

  .ens-card-content {
    position: relative;
    z-index: 2;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 2.5rem 2rem 2rem;
    text-align: center;
  }

  .ens-avatar {
    width: 80px;
    height: 80px;
    margin-bottom: 1.25rem;
    flex-shrink: 0;
  }

  .ens-avatar-img {
    width: 100%;
    height: 100%;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid rgba(255, 255, 255, 0.1);
  }

  .ens-avatar-fallback {
    width: 100%;
    height: 100%;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.06);
    border: 2px solid rgba(255, 255, 255, 0.1);
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .ens-avatar-fallback svg {
    width: 36px;
    height: 36px;
    color: rgba(255, 255, 255, 0.4);
  }

  .ens-name {
    font-size: 1.5rem;
    font-weight: 700;
    color: #f0f0f0;
    margin: 0 0 0.375rem;
    line-height: 1.2;
  }

  .ens-address {
    font-size: 0.8125rem;
    font-family: "SF Mono", Menlo, Monaco, "Courier New", monospace;
    color: rgba(255, 255, 255, 0.4);
    margin: 0 0 1rem;
    letter-spacing: 0.02em;
  }

  .ens-description {
    font-size: 0.9375rem;
    line-height: 1.6;
    color: rgba(255, 255, 255, 0.6);
    margin: 0 0 1.25rem;
    max-width: 280px;
  }

  .ens-socials {
    display: flex;
    gap: 0.75rem;
    margin-top: auto;
  }

  .ens-social-link {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid rgba(255, 255, 255, 0.08);
    color: rgba(255, 255, 255, 0.5);
    text-decoration: none;
    transition:
      background 0.2s ease,
      color 0.2s ease,
      border-color 0.2s ease;
  }

  .ens-social-link:hover {
    background: rgba(255, 255, 255, 0.12);
    color: rgba(255, 255, 255, 0.9);
    border-color: rgba(255, 255, 255, 0.2);
  }

  .ens-social-link svg {
    width: 16px;
    height: 16px;
  }

  @media (max-width: 768px) {
    .ens-card-wrapper {
      max-width: 320px;
    }

    .ens-card-content {
      padding: 2rem 1.5rem 1.75rem;
    }

    .ens-name {
      font-size: 1.25rem;
    }
  }
</style>

<script>
  function initEnsCard() {
    const card = document.querySelector<HTMLElement>("[data-ens-card]");
    if (!card || card.dataset.ensCardInitialized) return;
    card.dataset.ensCardInitialized = "true";

    const prefersReducedMotion = window.matchMedia(
      "(prefers-reduced-motion: reduce)",
    );
    if (prefersReducedMotion.matches) return;

    const shine = document.querySelector<HTMLElement>("[data-ens-shine]");
    if (!shine) return;

    const MAX_ROTATION = 15;
    const NEUTRAL_BETA = 45;
    const BETA_SENSITIVITY_RANGE = 45;

    function handleMouseMove(e: MouseEvent) {
      const rect = card!.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;

      const mouseX = e.clientX - centerX;
      const mouseY = e.clientY - centerY;

      const rotateY = (mouseX / (rect.width / 2)) * MAX_ROTATION;
      const rotateX = -(mouseY / (rect.height / 2)) * MAX_ROTATION;

      card!.style.transform = `rotateX(${rotateX}deg) rotateY(${rotateY}deg)`;

      const shineX = ((e.clientX - rect.left) / rect.width) * 100;
      const shineY = ((e.clientY - rect.top) / rect.height) * 100;
      shine!.style.background = `radial-gradient(
        circle at ${shineX}% ${shineY}%,
        rgba(255, 219, 112, 0.25) 0%,
        rgba(132, 50, 255, 0.12) 30%,
        transparent 60%
      )`;
      shine!.style.opacity = "1";
    }

    function handleMouseLeave() {
      card!.style.transition = "transform 0.5s ease-out";
      card!.style.transform = "rotateX(0deg) rotateY(0deg)";
      shine!.style.opacity = "0";

      setTimeout(() => {
        card!.style.transition = "transform 0.1s ease-out";
      }, 500);
    }

    card.addEventListener("mousemove", handleMouseMove);
    card.addEventListener("mouseleave", handleMouseLeave);

    // Mobile: DeviceOrientation for gyro-based tilt
    function handleOrientation(e: DeviceOrientationEvent) {
      if (e.gamma === null || e.beta === null) return;

      const rotateY = (e.gamma / 90) * MAX_ROTATION;
      const rotateX = Math.max(
        -MAX_ROTATION,
        Math.min(
          MAX_ROTATION,
          ((e.beta - NEUTRAL_BETA) / BETA_SENSITIVITY_RANGE) * MAX_ROTATION,
        ),
      );

      card!.style.transform = `rotateX(${rotateX}deg) rotateY(${rotateY}deg)`;
      shine!.style.opacity = "0.6";
    }

    // Only add gyro on touch devices
    if ("ontouchstart" in window) {
      if (
        typeof DeviceOrientationEvent !== "undefined" &&
        typeof (DeviceOrientationEvent as any).requestPermission === "function"
      ) {
        card.addEventListener(
          "click",
          () => {
            (DeviceOrientationEvent as any)
              .requestPermission()
              .then((response: string) => {
                if (response === "granted") {
                  window.addEventListener(
                    "deviceorientation",
                    handleOrientation,
                  );
                }
              })
              .catch(() => {});
          },
          { once: true },
        );
      } else if (typeof DeviceOrientationEvent !== "undefined") {
        window.addEventListener("deviceorientation", handleOrientation);
      }
    }

    // Listen for reduced motion changes
    const handleReducedMotionChange = (e: MediaQueryListEvent) => {
      if (e.matches) {
        card!.style.transform = "";
        shine!.style.opacity = "0";
        card!.removeEventListener("mousemove", handleMouseMove);
        card!.removeEventListener("mouseleave", handleMouseLeave);
        window.removeEventListener("deviceorientation", handleOrientation);
        prefersReducedMotion.removeEventListener(
          "change",
          handleReducedMotionChange,
        );
      }
    };
    prefersReducedMotion.addEventListener("change", handleReducedMotionChange);

    // Cleanup on Astro page swap to prevent memory leaks
    document.addEventListener(
      "astro:before-swap",
      () => {
        card!.removeEventListener("mousemove", handleMouseMove);
        card!.removeEventListener("mouseleave", handleMouseLeave);
        window.removeEventListener("deviceorientation", handleOrientation);
        prefersReducedMotion.removeEventListener(
          "change",
          handleReducedMotionChange,
        );
      },
      { once: true },
    );
  }

  document.addEventListener("astro:page-load", initEnsCard);
</script>

