---
// Aboutセクション - スクロールアニメーション付き
import { SITE } from "../../config/site";
import { getEnsProfile } from "../../utils/ens";
import EnsProfileCard from "./EnsProfileCard.astro";

const ensProfile = await getEnsProfile(SITE.ensName);
---

<section id="about" class="about-section">
  <div class="about-container">
    <div class="about-header" data-animate="fade-up">
      <span class="section-label">About</span>
      <h2 class="section-title">Who I Am</h2>
    </div>

    <div class="about-content">
      <div class="about-text" data-animate="fade-up">
        <p>
          ソフトウェアエンジニアとして、美しく機能的なデジタル体験の創造に情熱を注いでいます。
        </p>
        <p>
          モダンなWeb技術に焦点を当て、パフォーマンスとアクセシビリティの両立を追求しています。
        </p>
      </div>

      <div class="about-stats" data-animate="stagger">
        <div class="stat-item">
          <span class="stat-number">5+</span>
          <span class="stat-label">Years Experience</span>
        </div>
        <div class="stat-item">
          <span class="stat-number">50+</span>
          <span class="stat-label">Projects</span>
        </div>
        <div class="stat-item">
          <span class="stat-number">&infin;</span>
          <span class="stat-label">Curiosity</span>
        </div>
      </div>
    </div>

    {ensProfile && (
      <div class="ens-section" data-animate="fade-up">
        <EnsProfileCard profile={ensProfile} />
      </div>
    )}
  </div>
</section>

<style>
  .about-section {
    min-height: 100vh;
    display: flex;
    align-items: center;
    padding: 8rem 2rem;
    background: #fff;
  }

  .about-container {
    max-width: 1200px;
    margin: 0 auto;
    width: 100%;
  }

  .section-label {
    display: block;
    font-size: 0.875rem;
    letter-spacing: 0.3em;
    text-transform: uppercase;
    color: #888;
    margin-bottom: 0.5rem;
  }

  .section-title {
    font-size: clamp(2.5rem, 8vw, 5rem);
    font-weight: 700;
    margin: 0 0 4rem;
    line-height: 1.1;
    color: #1a1a1a;
  }

  .about-content {
    display: grid;
    grid-template-columns: 1.5fr 1fr;
    gap: 4rem;
    align-items: start;
  }

  .about-text p {
    font-size: 1.25rem;
    line-height: 2;
    color: #444;
    margin-bottom: 1.5rem;
  }

  .about-text p:last-child {
    margin-bottom: 0;
  }

  .about-stats {
    display: flex;
    flex-direction: column;
    gap: 2.5rem;
  }

  .stat-item {
    display: flex;
    flex-direction: column;
    padding-left: 1.5rem;
    border-left: 2px solid #1a1a1a;
  }

  .stat-number {
    font-size: 3.5rem;
    font-weight: 700;
    line-height: 1;
    color: #1a1a1a;
  }

  .stat-label {
    font-size: 0.875rem;
    color: #666;
    margin-top: 0.5rem;
    letter-spacing: 0.1em;
    text-transform: uppercase;
  }

  .ens-section {
    margin-top: 4rem;
    display: flex;
    justify-content: center;
  }

  @media (max-width: 768px) {
    .about-section {
      padding: 6rem 1.5rem;
    }

    .about-content {
      grid-template-columns: 1fr;
      gap: 3rem;
    }

    .about-stats {
      flex-direction: row;
      justify-content: space-between;
      flex-wrap: wrap;
    }

    .stat-item {
      flex: 1;
      min-width: 100px;
      padding-left: 1rem;
    }

    .stat-number {
      font-size: 2.5rem;
    }

    .about-text p {
      font-size: 1.125rem;
    }
  }
</style>

