---
import "../styles/global.css";
import Footer from "../components/Footer.astro";
import Header from "../components/Header.astro";
import { SITE } from "../config/site";
import { generateWebSiteSchema, stringifySchema } from "../utils/schema";

interface Props {
	title?: string;
	description?: string;
	ogImage?: string;
	ogImageAlt?: string;
	ogSiteName?: string;
	ogType?: "website" | "article" | "book";
	noHeader?: boolean;
	noFooter?: boolean;
	enableSmoothScroll?: boolean;
}

const {
	title = SITE.name,
	description = SITE.description,
	ogImage = "/og-image.png",
	ogImageAlt = title,
	ogSiteName = SITE.name,
	ogType = "website",
	noHeader = false,
	noFooter = false,
	enableSmoothScroll = false,
} = Astro.props;

const canonicalURL = new URL(Astro.url.pathname, Astro.site);
const ogImageURL = new URL(ogImage, Astro.site);
---

<!doctype html>
<html lang="ja" class:list={[{ lenis: enableSmoothScroll }]}>
	<head>
		<meta charset="UTF-8" />
		<meta name="viewport" content="width=device-width" />
		<link rel="icon" type="image/svg+xml" href="/favicon.svg" />
		<meta name="generator" content={Astro.generator} />
		<meta name="color-scheme" content="light dark" />

		<!-- Prevent flash of wrong theme -->
		<script is:inline>
			(function() {
				const theme = localStorage.getItem("theme");
				const prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
				if (theme === "dark" || (!theme && prefersDark)) {
					document.documentElement.classList.add("dark");
				}
			})();
		</script>

		<!-- Primary Meta Tags -->
		<title>{title}</title>
		<meta name="title" content={title} />
		<meta name="description" content={description} />
		<meta name="author" content={SITE.author} />
		<link rel="canonical" href={canonicalURL} />

		<!-- Open Graph / Facebook -->
		<meta property="og:type" content={ogType} />
		<meta property="og:url" content={canonicalURL} />
		<meta property="og:title" content={title} />
		<meta property="og:description" content={description} />
		<meta property="og:image" content={ogImageURL} />
		<meta property="og:image:alt" content={ogImageAlt} />
		<meta property="og:site_name" content={ogSiteName} />
		<meta property="og:locale" content={SITE.locale} />

		<!-- Twitter -->
		<meta name="twitter:card" content="summary_large_image" />
		<meta name="twitter:url" content={canonicalURL} />
		<meta name="twitter:title" content={title} />
		<meta name="twitter:description" content={description} />
		<meta name="twitter:image" content={ogImageURL} />
		<meta name="twitter:image:alt" content={ogImageAlt} />

		<!-- 構造化データ (JSON-LD) -->
		<script
			type="application/ld+json"
			set:html={stringifySchema(generateWebSiteSchema(Astro.site?.href || SITE.url))}
		></script>
		<slot name="head" />
	</head>
	<body class="bg-white text-gray-900 transition-colors dark:bg-gray-900 dark:text-gray-100">
		<!-- スキップリンク -->
		<a href="#main-content" class="skip-link">
			コンテンツにスキップ
		</a>
		{!noHeader && <Header />}
		<div id="main-content">
			<slot />
		</div>
		{!noFooter && <Footer />}
	</body>
</html>

<style>
	html,
	body {
		margin: 0;
		width: 100%;
		height: 100%;
		font-family: "Shippori Mincho", serif;
	}

	/* スキップリンク */
	.skip-link {
		position: absolute;
		top: -100%;
		left: 50%;
		transform: translateX(-50%);
		padding: 0.75rem 1.5rem;
		background: var(--primary-color);
		color: white;
		font-weight: 600;
		border-radius: 0 0 0.5rem 0.5rem;
		text-decoration: none;
		z-index: 50;
		transition: top 0.2s ease-out;
	}

	.skip-link:focus-visible {
		top: 0;
	}

	@media (prefers-reduced-motion: reduce) {
		.skip-link {
			transition: none;
		}
	}

	/* Lenis smooth scroll styles */
	html.lenis,
	html.lenis body {
		height: auto;
	}

	.lenis.lenis-smooth {
		scroll-behavior: auto !important;
	}

	.lenis.lenis-smooth [data-lenis-prevent] {
		overscroll-behavior: contain;
	}

	.lenis.lenis-stopped {
		overflow: hidden;
	}

	.lenis.lenis-scrolling iframe {
		pointer-events: none;
	}
</style>

