      (window as Window & { openGlobalSearch: () => void }).openGlobalSearch();
    }
  }

  desktopSearchBtn?.addEventListener("click", handleSearchClick);
  mobileSearchBtn?.addEventListener("click", handleSearchClick);
</script>

