---
// フィルタリング・ソートコンポーネント
// クライアントサイドでリストのフィルタ・ソートを行う

interface Props {
	tags: string[];
	sortOptions?: { value: string; label: string }[];
	containerId: string;
}

const {
	tags,
	sortOptions = [
		{ value: "date-desc", label: "新しい順" },
		{ value: "date-asc", label: "古い順" },
		{ value: "title", label: "タイトル順" },
	],
	containerId,
} = Astro.props;

// 重複を排除してソート
const uniqueTags = [...new Set(tags)].sort();
---

<div class="mb-8 space-y-4" data-filter-sort data-container={containerId}>
  <!-- フィルターとソート -->
  <div class="flex flex-wrap items-center justify-between gap-4">
    <!-- フィルター -->
    {uniqueTags.length > 0 && (
      <div class="flex flex-wrap items-center gap-2">
        <span class="text-sm font-medium text-gray-600 dark:text-gray-400">タグ:</span>
        <button
          type="button"
          class="filter-chip active"
          data-tag="all"
        >
          すべて
        </button>
        {uniqueTags.map((tag) => (
          <button
            type="button"
            class="filter-chip"
            data-tag={tag}
          >
            {tag}
          </button>
        ))}
      </div>
    )}

    <!-- ソート -->
    <div class="flex items-center gap-2">
      <label for={`sort-${containerId}`} class="text-sm font-medium text-gray-600 dark:text-gray-400">
        並び替え:
      </label>
      <select
        id={`sort-${containerId}`}
        class="sort-select rounded-lg border border-gray-300 bg-white px-3 py-1.5 text-sm transition-colors focus:border-[var(--primary-color)] focus:outline-none focus:ring-2 focus:ring-[var(--primary-color)] focus:ring-offset-1 dark:border-gray-600 dark:bg-gray-800 dark:text-white"
      >
        {sortOptions.map((option) => (
          <option value={option.value}>{option.label}</option>
        ))}
      </select>
    </div>
  </div>

  <!-- アクティブフィルター表示エリア -->
  <div class="active-filter-area hidden items-center gap-2">
    <span class="text-sm text-gray-500 dark:text-gray-400">選択中:</span>
    <span class="active-filter-tag inline-flex items-center gap-1 rounded-full bg-[var(--primary-color)] px-3 py-1 text-sm font-medium text-white dark:text-gray-900"></span>
    <button
      type="button"
      class="reset-filter-btn ml-2 text-sm text-gray-500 underline transition-colors hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200"
    >
      リセット
    </button>
  </div>

  <!-- 結果数表示 -->
  <div class="flex items-center justify-between text-sm text-gray-500 dark:text-gray-400">
    <span class="result-count"></span>
  </div>

  <!-- 空の検索結果状態 -->
  <div class="empty-state hidden py-12 text-center" role="status" aria-live="polite">
    <div class="mb-4 text-gray-400 dark:text-gray-500">
      <svg
        class="mx-auto h-12 w-12"
        fill="none"
