      条件を変更して再度お試しください
    </p>
    <button
      type="button"
      class="reset-all-btn rounded-full border border-[var(--primary-color)] px-4 py-2 text-sm font-medium text-[var(--primary-color)] transition-colors hover:bg-[var(--primary-color)] hover:text-white dark:hover:text-gray-900"
    >
      フィルターをリセット
    </button>
  </div>
</div>

<style>
  .filter-chip {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    border-radius: 9999px;
    border: 1px solid var(--border-color);
    padding: 0.25rem 0.75rem;
    font-size: 0.875rem;
    font-weight: 500;
    transition: all 0.2s ease;
    background-color: var(--bg-primary);
    color: var(--text-secondary);
  }

  .filter-chip:hover {
    border-color: var(--primary-color);
    color: var(--primary-color);
  }

  .filter-chip:focus-visible {
    outline: 2px solid var(--primary-color);
    outline-offset: 2px;
  }

  .filter-chip.active {
    border-color: var(--primary-color);
    background-color: var(--primary-color);
    color: white;
  }

  :root.dark .filter-chip.active {
    color: #1f2937;
  }

  /* Smooth filter transition */
  [data-item] {
    transition: opacity 0.2s ease, transform 0.2s ease;
  }

  [data-item].filter-hidden {
    opacity: 0;
    transform: scale(0.95);
    pointer-events: none;
    position: absolute;
    visibility: hidden;
  }

  @media (prefers-reduced-motion: reduce) {
    .filter-chip,
    [data-item] {
      transition: none;
    }
  }
</style>

<script is:inline>
  (function() {
    document.querySelectorAll("[data-filter-sort]").forEach(function(filterComponent) {
      const containerId = filterComponent.dataset.container;
      const container = document.getElementById(containerId);
      if (!container) return;

      const items = Array.from(container.querySelectorAll("[data-item]"));
      const filterChips = filterComponent.querySelectorAll(".filter-chip");
      const sortSelect = filterComponent.querySelector(".sort-select");
      const resultCount = filterComponent.querySelector(".result-count");
      const activeFilterArea = filterComponent.querySelector(".active-filter-area");
      const activeFilterTag = filterComponent.querySelector(".active-filter-tag");
      const resetFilterBtn = filterComponent.querySelector(".reset-filter-btn");
      const emptyState = filterComponent.querySelector(".empty-state");
      const resetAllBtn = filterComponent.querySelector(".reset-all-btn");

      let currentTag = "all";
      let currentSort = "date-desc";

      function resetToAll() {
        currentTag = "all";
        filterChips.forEach(function(chip) {
          chip.classList.remove("active");
          if (chip.dataset.tag === "all") {
            chip.classList.add("active");
          }
        });
        filterAndSort();
      }

      function updateActiveFilterArea() {
        if (currentTag === "all") {
          activeFilterArea.classList.add("hidden");
          activeFilterArea.classList.remove("flex");
        } else {
          activeFilterArea.classList.remove("hidden");
          activeFilterArea.classList.add("flex");
          activeFilterTag.textContent = currentTag;
        }
      }

      function updateResultCount(count, total) {
        if (resultCount) {
          if (currentTag === "all") {
            resultCount.textContent = total + "件を表示中";
          } else {
            resultCount.textContent = count + " / " + total + "件を表示中";
          }
        }
      }

      function updateEmptyState(count) {
        if (count === 0) {
          emptyState.classList.remove("hidden");
          container.classList.add("hidden");
        } else {
          emptyState.classList.add("hidden");
          container.classList.remove("hidden");
        }
      }

      function filterAndSort() {
        // Get sort value
        if (sortSelect) {
          currentSort = sortSelect.value;
        }

        // Filter
        const filteredItems = items.filter(function(item) {
          if (currentTag === "all") return true;
          const itemTags = item.dataset.tags ? item.dataset.tags.split(",") : [];
          return itemTags.includes(currentTag);
        });

        // Sort
        filteredItems.sort(function(a, b) {
          if (currentSort === "date-desc") {
            const aDate = new Date(a.dataset.date || 0).getTime();
            const bDate = new Date(b.dataset.date || 0).getTime();
            return bDate - aDate;
          } else if (currentSort === "date-asc") {
            const aDate = new Date(a.dataset.date || 0).getTime();
            const bDate = new Date(b.dataset.date || 0).getTime();
            return aDate - bDate;
          } else if (currentSort === "title") {
            const aTitle = a.dataset.title || "";
            const bTitle = b.dataset.title || "";
            return aTitle.localeCompare(bTitle, "ja");
          }
          return 0;
        });

        // Update visibility with smooth transition
        items.forEach(function(item) {
          if (!filteredItems.includes(item)) {
            item.classList.add("filter-hidden");
            item.style.order = "999";
          }
        });

        filteredItems.forEach(function(item, index) {
          item.classList.remove("filter-hidden");
          item.style.order = String(index);
        });

        updateResultCount(filteredItems.length, items.length);
        updateActiveFilterArea();
        updateEmptyState(filteredItems.length);
      }

      // Tag filter click handlers
      filterChips.forEach(function(chip) {
        chip.addEventListener("click", function() {
          currentTag = chip.dataset.tag;

          // Update active state
          filterChips.forEach(function(c) {
            c.classList.remove("active");
          });
          chip.classList.add("active");

          filterAndSort();
        });
      });

      // Sort change handler
      if (sortSelect) {
        sortSelect.addEventListener("change", filterAndSort);
      }

      // Reset filter handlers
      if (resetFilterBtn) {
        resetFilterBtn.addEventListener("click", resetToAll);
      }
      if (resetAllBtn) {
        resetAllBtn.addEventListener("click", resetToAll);
      }

      // Initial display
      filterAndSort();
    });
  })();
</script>

