      <svg
        id="menu-icon-open"
        class="h-6 w-6"
        fill="none"
        stroke="currentColor"
        viewBox="0 0 24 24"
        aria-hidden="true"
      >
        <path
          stroke-linecap="round"
          stroke-linejoin="round"
          stroke-width="2"
          d="M4 6h16M4 12h16M4 18h16"></path>
      </svg>
      <svg
        id="menu-icon-close"
        class="hidden h-6 w-6"
        fill="none"
        stroke="currentColor"
        viewBox="0 0 24 24"
