          stroke-linejoin="round"
          stroke-width="2"
          d="M6 18L18 6M6 6l12 12"></path>
      </svg>
      </button>
    </div>
  </nav>

  <!-- モバイルメニュー -->
  <div
    id="mobile-menu"
