    <ul class="space-y-1 px-6 py-4">
      {
        NAV_LINKS.map((link) => (
          <li>
            <NavLink
              href={link.href}
              class="block rounded-lg px-4 py-3 text-lg hover:bg-gray-100 dark:hover:bg-gray-800"
