117→<style>
118→  .filter-chip {
119→    display: inline-flex;
120→    align-items: center;
121→    gap: 0.25rem;
122→    border-radius: 9999px;
123→    border: 1px solid var(--border-color);
124→    padding: 0.25rem 0.75rem;
125→    font-size: 0.875rem;
126→    font-weight: 500;
127→    transition: all 0.2s ease;
128→    background-color: var(--bg-primary);
129→    color: var(--text-secondary);
130→  }
131→
132→  .filter-chip:hover {
133→    border-color: var(--primary-color);
134→    color: var(--primary-color);
135→  }
136→
137→  .filter-chip:focus-visible {
138→    outline: 2px solid var(--primary-color);
139→    outline-offset: 2px;
140→  }
141→
142→  .filter-chip.active {
143→    border-color: var(--primary-color);
144→    background-color: var(--primary-color);
145→    color: white;
146→  }
147→
148→  @media (prefers-color-scheme: dark) {
149→    .filter-chip.active {
150→      color: #1f2937;
151→    }
152→  }
153→
154→  /* Smooth filter transition */
155→  [data-item] {
156→    transition: opacity 0.2s ease, transform 0.2s ease;
157→  }
158→
159→  [data-item].filter-hidden {
160→    opacity: 0;
161→    transform: scale(0.95);
162→    pointer-events: none;
163→    position: absolute;
164→    visibility: hidden;
165→  }
166→
167→  @media (prefers-reduced-motion: reduce) {
168→    .filter-chip,
169→    [data-item] {
170→      transition: none;
171→    }
172→  }
173→</style>
174→
175→<script is:inline>
176→  (function() {
177→    document.querySelectorAll("[data-filter-sort]").forEach(function(filterComponent) {
178→      const containerId = filterComponent.dataset.container;
179→      const container = document.getElementById(containerId);
180→      if (!container) return;
181→
182→      const items = Array.from(container.querySelectorAll("[data-item]"));
183→      const filterChips = filterComponent.querySelectorAll(".filter-chip");
184→      const sortSelect = filterComponent.querySelector(".sort-select");
185→      const resultCount = filterComponent.querySelector(".result-count");
186→      const activeFilterArea = filterComponent.querySelector(".active-filter-area");
187→      const activeFilterTag = filterComponent.querySelector(".active-filter-tag");
188→      const resetFilterBtn = filterComponent.querySelector(".reset-filter-btn");
189→      const emptyState = filterComponent.querySelector(".empty-state");
190→      const resetAllBtn = filterComponent.querySelector(".reset-all-btn");
191→
192→      let currentTag = "all";
193→      let currentSort = "date-desc";
194→
195→      function resetToAll() {
196→        currentTag = "all";
197→        filterChips.forEach(function(chip) {
198→          chip.classList.remove("active");
199→          if (chip.dataset.tag === "all") {
200→            chip.classList.add("active");
201→          }
202→        });
203→        filterAndSort();
204→      }
205→
206→      function updateActiveFilterArea() {
207→        if (currentTag === "all") {
208→          activeFilterArea.classList.add("hidden");
209→          activeFilterArea.classList.remove("flex");
210→        } else {
211→          activeFilterArea.classList.remove("hidden");
212→          activeFilterArea.classList.add("flex");
213→          activeFilterTag.textContent = currentTag;
214→        }
215→      }
216→
217→      function updateResultCount(count, total) {
218→        if (resultCount) {
219→          if (currentTag === "all") {
220→            resultCount.textContent = total + "件を表示中";
221→          } else {
222→            resultCount.textContent = count + " / " + total + "件を表示中";
223→          }
224→        }
225→      }
226→
227→      function updateEmptyState(count) {
228→        if (count === 0) {
229→          emptyState.classList.remove("hidden");
230→          container.classList.add("hidden");
231→        } else {
232→          emptyState.classList.add("hidden");
233→          container.classList.remove("hidden");
234→        }
235→      }
236→
237→      function filterAndSort() {
238→        // Get sort value
239→        if (sortSelect) {
240→          currentSort = sortSelect.value;
241→        }
242→
243→        // Filter
244→        const filteredItems = items.filter(function(item) {
245→          if (currentTag === "all") return true;
246→          const itemTags = item.dataset.tags ? item.dataset.tags.split(",") : [];
247→          return itemTags.includes(currentTag);
248→        });
249→
250→        // Sort
251→        filteredItems.sort(function(a, b) {
252→          if (currentSort === "date-desc") {
253→            const aDate = new Date(a.dataset.date || 0).getTime();
254→            const bDate = new Date(b.dataset.date || 0).getTime();
255→            return bDate - aDate;
256→          } else if (currentSort === "date-asc") {
257→            const aDate = new Date(a.dataset.date || 0).getTime();
258→            const bDate = new Date(b.dataset.date || 0).getTime();
259→            return aDate - bDate;
260→          } else if (currentSort === "title") {
261→            const aTitle = a.dataset.title || "";
262→            const bTitle = b.dataset.title || "";
263→            return aTitle.localeCompare(bTitle, "ja");
264→          }
265→          return 0;
266→        });
267→
268→        // Update visibility with smooth transition
269→        items.forEach(function(item) {
270→          if (!filteredItems.includes(item)) {
271→            item.classList.add("filter-hidden");
272→            item.style.order = "999";
273→          }
274→        });
275→
276→        filteredItems.forEach(function(item, index) {
277→          item.classList.remove("filter-hidden");
278→          item.style.order = String(index);
279→        });
280→
281→        updateResultCount(filteredItems.length, items.length);
282→        updateActiveFilterArea();
283→        updateEmptyState(filteredItems.length);
284→      }
285→
286→      // Tag filter click handlers
287→      filterChips.forEach(function(chip) {
288→        chip.addEventListener("click", function() {
289→          currentTag = chip.dataset.tag;
290→
291→          // Update active state
292→          filterChips.forEach(function(c) {
293→            c.classList.remove("active");
294→          });
295→          chip.classList.add("active");
296→
297→          filterAndSort();
298→        });
299→      });
300→
301→      // Sort change handler
302→      if (sortSelect) {
303→        sortSelect.addEventListener("change", filterAndSort);
304→      }
305→
306→      // Reset filter handlers
307→      if (resetFilterBtn) {
308→        resetFilterBtn.addEventListener("click", resetToAll);
309→      }
310→      if (resetAllBtn) {
311→        resetAllBtn.addEventListener("click", resetToAll);
312→      }
313→
314→      // Initial display
315→      filterAndSort();
316→    });
317→  })();
318→</script>
