  6→/* テーマカラー - ライトモード */
  7→:root {
  8→	--primary-color: #4f46e5;
  9→	--bg-primary: #ffffff;
 10→	--bg-secondary: #f8fafc;
 11→	--bg-tertiary: #f1f5f9;
 12→	--text-primary: #1a1a1a;
 13→	--text-secondary: #4b5563;
 14→	--text-muted: #9ca3af;
 15→	--border-color: #e2e8f0;
 16→	--link-color: #2563eb;
 17→	--link-hover-color: #1d4ed8;
 18→	--blockquote-bg: #eff6ff;
 19→	--blockquote-border: #3b82f6;
 20→	--code-bg: #f1f5f9;
 21→	--code-text: #1e293b;
 22→}
 23→
 24→/* テーマカラー - ダークモード（ブラウザ設定に自動追従） */
 25→@media (prefers-color-scheme: dark) {
 26→	:root {
 27→		--primary-color: #818cf8;
 28→		--bg-primary: #0f172a;
 29→		--bg-secondary: #1e293b;
 30→		--bg-tertiary: #334155;
 31→		--text-primary: #f1f5f9;
 32→		--text-secondary: #cbd5e1;
 33→		--text-muted: #64748b;
 34→		--border-color: #334155;
 35→		--link-color: #60a5fa;
 36→		--link-hover-color: #93c5fd;
 37→		--blockquote-bg: #1e3a5f;
 38→		--blockquote-border: #3b82f6;
 39→		--code-bg: #1e293b;
 40→		--code-text: #e2e8f0;
 41→	}
 42→}
 43→
 44→/* フォーカス表示の強化 */
 45→:focus-visible {
 46→	outline: 2px solid var(--primary-color);
 47→	outline-offset: 2px;
 48→}
 49→
 50→/* デフォルトのoutlineを消してfocus-visibleで制御 */
 51→:focus:not(:focus-visible) {
 52→	outline: none;
 53→}
 54→
 55→/* Code block styles */
 56→.prose pre {
 57→	position: relative;
 58→	padding: 1rem;
 59→	border-radius: 0.5rem;
 60→	overflow-x: auto;
 61→}
 62→
 63→.prose pre code {
 64→	font-family: "SF Mono", Menlo, Monaco, "Courier New", monospace;
 65→	font-size: 0.875rem;
 66→	line-height: 1.6;
 67→}
 68→
 69→/* Code block copy button */
 70→.prose pre .copy-button {
 71→	position: absolute;
 72→	top: 0.5rem;
 73→	right: 0.5rem;
 74→	padding: 0.375rem;
 75→	background: rgba(255, 255, 255, 0.1);
 76→	border: none;
 77→	border-radius: 0.375rem;
 78→	cursor: pointer;
 79→	opacity: 0;
 80→	transition: opacity 0.2s;
 81→}
 82→
 83→.prose pre:hover .copy-button {
 84→	opacity: 1;
 85→}
 86→
 87→.prose pre .copy-button:hover {
 88→	background: rgba(255, 255, 255, 0.2);
 89→}
 90→
 91→.prose pre .copy-button svg {
 92→	width: 1rem;
 93→	height: 1rem;
 94→	color: #a0aec0;
 95→}
 96→
 97→.prose pre .copy-button.copied svg {
 98→	color: #48bb78;
 99→}
100→
101→/* Inline code */
102→.prose :not(pre) > code {
103→	background: var(--code-bg);
104→	padding: 0.125rem 0.375rem;
105→	border-radius: 0.25rem;
106→	font-size: 0.875em;
107→	font-weight: 500;
108→	color: var(--code-text);
109→}
110→
111→/* Better heading anchors */
112→.prose h2,
113→.prose h3,
114→.prose h4 {
115→	scroll-margin-top: 4rem;
116→}
117→
118→/* Blockquote styling */
119→.prose blockquote {
120→	border-left-color: var(--blockquote-border);
121→	background: var(--blockquote-bg);
122→	padding: 1rem;
123→	border-radius: 0 0.5rem 0.5rem 0;
124→	font-style: normal;
125→}
126→
127→.prose blockquote p {
128→	margin: 0;
129→}
130→
131→/* Table styling */
132→.prose table {
133→	width: 100%;
134→	border-collapse: collapse;
135→}
136→
137→.prose th {
138→	background: var(--bg-secondary);
139→	font-weight: 600;
140→}
141→
142→.prose th,
143→.prose td {
144→	border: 1px solid var(--border-color);
145→	padding: 0.75rem;
146→}
147→
148→.prose tr:hover {
149→	background: var(--bg-secondary);
150→}
151→
152→/* Task list styling */
153→.prose ul:has(input[type="checkbox"]) {
154→	list-style: none;
155→	padding-left: 0;
156→}
157→
158→.prose li:has(> input[type="checkbox"]) {
159→	display: flex;
160→	align-items: flex-start;
161→	gap: 0.5rem;
162→}
163→
164→.prose input[type="checkbox"] {
165→	margin-top: 0.375rem;
166→	accent-color: #3b82f6;
167→}
168→
169→/* Image styling */
170→.prose img {
171→	border-radius: 0.5rem;
172→	box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1);
173→}
174→
175→/* Link styling */
176→.prose a {
177→	color: var(--link-color);
178→	text-decoration: underline;
179→	text-underline-offset: 2px;
180→}
181→
182→.prose a:hover {
183→	color: var(--link-hover-color);
184→}
185→
186→/* Scroll-triggered fade-in animation */
187→[data-animate] {
188→	opacity: 0;
189→	transform: translateY(20px);
190→	transition:
191→		opacity 0.6s ease,
192→		transform 0.6s ease;
193→}
194→
195→[data-animate].is-visible {
196→	opacity: 1;
197→	transform: translateY(0);
198→}
199→
200→/* Reduced motion preference */
201→@media (prefers-reduced-motion: reduce) {
202→	[data-animate] {
203→		opacity: 1;
204→		transform: none;
205→		transition: none;
206→	}
207→
208→	*,
209→	*::before,
210→	*::after {
211→		animation-duration: 0.01ms !important;
212→		animation-iteration-count: 1 !important;
213→		transition-duration: 0.01ms !important;
214→		scroll-behavior: auto !important;
215→	}
216→}
