 1→---
 2→import { Image } from "astro:assets";
 3→import { getCollection } from "astro:content";
 4→import FilterSort from "../../components/FilterSort.astro";
 5→import Badge from "../../components/ui/Badge.astro";
 6→import Tag from "../../components/ui/Tag.astro";
 7→import { SITE } from "../../config/site";
 8→import Layout from "../../layouts/Layout.astro";
 9→import { formatDate } from "../../utils/date";
10→
11→const books = await getCollection("books");
12→
13→const sortedBooks = [...books].sort((a, b) => {
14→	const aTime = a.data.finishedDate?.getTime() ?? 0;
15→	const bTime = b.data.finishedDate?.getTime() ?? 0;
16→	return bTime - aTime;
17→});
18→
19→// すべてのタグを収集（カテゴリ + タグ）
20→const allTags = books.flatMap((book) => [
21→	...(book.data.category ? [book.data.category] : []),
22→	...book.data.tags,
23→]);
24→
25→// ステータスに基づくソートオプション
26→const sortOptions = [
27→	{ value: "date-desc", label: "読了日（新しい順）" },
28→	{ value: "date-asc", label: "読了日（古い順）" },
29→	{ value: "title", label: "タイトル順" },
30→];
31→---
32→
33→<Layout
34→  title={`Bookshelf | ${SITE.name}`}
35→  description="読書記録と書評の一覧。読んだ本や積読のメモをまとめています。"
36→>
37→  <main class="mx-auto max-w-6xl px-6 py-12">
38→    <h1 class="mb-12 text-4xl font-bold">Bookshelf</h1>
39→
40→    <!-- フィルタリング・ソート -->
41→    <FilterSort tags={allTags} sortOptions={sortOptions} containerId="bookshelf-list" />
42→
43→    <div id="bookshelf-list" class="grid gap-8 sm:grid-cols-2 lg:grid-cols-3">
44→      {
45→        sortedBooks.map((book) => {
46→          const bookTags = [
47→            ...(book.data.category ? [book.data.category] : []),
48→            ...book.data.tags,
49→          ];
50→          return (
51→          <a
52→            href={`/bookshelf/${book.id}`}
53→            class="group block overflow-hidden rounded-lg border border-gray-200 transition-all duration-200 hover:-translate-y-1 hover:shadow-lg focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[var(--primary-color)] dark:border-gray-700"
54→            data-item
55→            data-tags={bookTags.join(",")}
56→            data-date={book.data.finishedDate?.toISOString() ?? ""}
57→            data-title={book.data.title}
58→          >
59→            <div class="aspect-[3/4] overflow-hidden bg-gray-100">
60→              <Image
61→                src={book.data.coverImage}
62→                alt={`${book.data.title} cover`}
63→                class="h-full w-full object-cover transition-transform group-hover:scale-105"
64→              />
65→            </div>
66→            <div class="p-4">
67→              <div class="mb-3 flex flex-wrap items-center gap-2">
68→                <Badge variant={book.data.status} />
69→                {book.data.category && <Tag>{book.data.category}</Tag>}
70→              </div>
71→              <h2 class="mb-1 text-xl font-bold">{book.data.title}</h2>
72→              <p class="mb-2 text-sm text-gray-600">{book.data.author}</p>
73→              {book.data.finishedDate && (
74→                <p class="mb-2 text-xs text-gray-500">
75→                  読了日: {formatDate(book.data.finishedDate)}
76→                </p>
77→              )}
78→              <p class="mb-3 text-sm text-gray-700">{book.data.excerpt}</p>
79→              <div class="flex flex-wrap gap-2">
80→                {book.data.tags.map((tag) => <Tag>{tag}</Tag>)}
81→              </div>
82→              {book.data.rating && (
83→                <p class="mt-3 text-xs text-gray-600">
84→                  評価: {book.data.rating} / 5
85→                </p>
86→              )}
87→            </div>
88→          </a>
89→        );})
90→      }
91→    </div>
92→  </main>
93→</Layout>
