  2→import type { CollectionEntry } from "astro:content";
  3→import { getCollection, render } from "astro:content";
  4→import Breadcrumb from "../../components/Breadcrumb.astro";
  5→import ShareButtons from "../../components/blog/ShareButtons.astro";
  6→import PostNavigation from "../../components/PostNavigation.astro";
  7→import RelatedPosts from "../../components/RelatedPosts.astro";
  8→import BackToTop from "../../components/ui/BackToTop.astro";
  9→import Tag from "../../components/ui/Tag.astro";
 10→import { SITE } from "../../config/site";
 11→import Layout from "../../layouts/Layout.astro";
 12→import { formatDate } from "../../utils/date";
 13→import { formatReadingTime, getReadingTime } from "../../utils/reading-time";
 14→import { generateBreadcrumbSchema, stringifySchema } from "../../utils/schema";
 15→
 16→export async function getStaticPaths() {
 17→	const blogPosts = await getCollection("blog");
 18→	// 公開日でソート（新しい順）
 19→	const sortedPosts = blogPosts.sort(
 20→		(a, b) => b.data.date.getTime() - a.data.date.getTime(),
 21→	);
 22→
 23→	return sortedPosts.map((post, index) => {
 24→		// 前後の記事（時系列順: prev=古い、next=新しい）
 25→		const prevPost = sortedPosts[index + 1];
 26→		const nextPost = sortedPosts[index - 1];
 27→
 28→		// 関連記事（同じタグを持つ記事、最大3件）
 29→		const currentTags = post.data.tags || [];
 30→		const relatedPosts = sortedPosts
 31→			.filter((p) => p.id !== post.id)
 32→			.filter((p) => p.data.tags?.some((t: string) => currentTags.includes(t)))
 33→			.slice(0, 3);
 34→
 35→		return {
 36→			params: { id: post.id },
 37→			props: {
 38→				post,
 39→				prevPost: prevPost
 40→					? { id: prevPost.id, title: prevPost.data.title }
 41→					: undefined,
 42→				nextPost: nextPost
 43→					? { id: nextPost.id, title: nextPost.data.title }
 44→					: undefined,
 45→				relatedPosts,
 46→			},
 47→		};
 48→	});
 49→}
 50→
 51→const { post, prevPost, nextPost, relatedPosts } = Astro.props;
 52→const { Content } = await render(post);
 53→const canonicalURL = new URL(Astro.url.pathname, Astro.site);
 54→const readingTime = getReadingTime(post.body || "");
 55→const readingTimeText = formatReadingTime(readingTime);
 56→const publishedTime = post.data.date.toISOString();
 57→const modifiedTime = post.data.updatedDate
 58→	? post.data.updatedDate.toISOString()
 59→	: publishedTime;
 60→const ogImageURL = new URL(`/og/blog/${post.id}.png`, Astro.site);
 61→const blogSchema = {
 62→	"@context": "https://schema.org",
 63→	"@type": "BlogPosting",
 64→	headline: post.data.title,
 65→	description: post.data.excerpt,
 66→	datePublished: publishedTime,
 67→	dateModified: modifiedTime,
 68→	author: {
 69→		"@type": "Person",
 70→		name: SITE.author,
 71→		url: Astro.site?.href,
 72→	},
 73→	image: ogImageURL.href,
 74→	mainEntityOfPage: canonicalURL.href,
 75→	inLanguage: SITE.lang,
 76→};
 77→const breadcrumbItems = [
 78→	{ label: "ホーム", href: "/" },
 79→	{ label: "ブログ", href: "/blog" },
 80→	{ label: post.data.title },
 81→];
 82→const siteUrl = Astro.site?.href || SITE.url;
 83→---
 84→
 85→<Layout
 86→  title={`${post.data.title} | Blog | ${SITE.name}`}
 87→  description={post.data.excerpt}
 88→  ogType="article"
 89→  ogImage={ogImageURL.href}
 90→  ogImageAlt={post.data.title}
 91→>
 92→  <Fragment slot="head">
 93→    <meta property="article:author" content={SITE.author} />
 94→    <meta property="article:published_time" content={publishedTime} />
 95→    {
 96→      post.data.updatedDate && (
 97→        <meta property="article:modified_time" content={modifiedTime} />
 98→      )
 99→    }
100→    <script
101→      type="application/ld+json"
102→      set:html={stringifySchema(blogSchema)}
103→    />
104→    <script
105→      type="application/ld+json"
106→      set:html={stringifySchema(generateBreadcrumbSchema(breadcrumbItems, siteUrl))}
107→    />
108→  </Fragment>
109→  <main class="mx-auto max-w-4xl px-6 py-12">
110→    <Breadcrumb items={breadcrumbItems} />
111→    <div class="mb-8">
112→      <a
113→        href="/blog"
114→        class="mb-4 inline-block text-sm text-gray-600 hover:text-gray-900"
115→      >
116→        ← Blog一覧へ戻る
117→      </a>
118→      <h1 class="mb-4 text-4xl font-bold">{post.data.title}</h1>
119→      <div class="flex flex-wrap items-center gap-4 text-gray-600">
120→        <time>
121→          {formatDate(post.data.date)}
122→          {
123→            post.data.updatedDate && (
124→              <span class="ml-2 text-sm">
125→                (更新: {formatDate(post.data.updatedDate)})
126→              </span>
127→            )
128→          }
129→        </time>
130→        <span class="text-sm">{readingTimeText}</span>
131→        {
132→          post.data.tags && post.data.tags.length > 0 && (
133→            <div class="flex flex-wrap gap-2">
134→              {post.data.tags.map((tag: string) => (
135→                <Tag>{tag}</Tag>
136→              ))}
137→            </div>
138→          )
139→        }
140→      </div>
141→    </div>
142→
143→    <article class="prose prose-lg max-w-none">
144→      <Content />
145→    </article>
146→
147→    <div class="mt-12 border-t border-gray-200 pt-8">
148→      <ShareButtons url={canonicalURL.href} title={post.data.title} />
149→    </div>
150→
151→    <PostNavigation prevPost={prevPost} nextPost={nextPost} />
152→
153→    <RelatedPosts posts={relatedPosts} />
154→  </main>
155→  <BackToTop />
