157→
158→<script>
159→  // Add copy buttons to all code blocks
160→  const copyIcon = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path d="M7 3.5A1.5 1.5 0 0 1 8.5 2h3.879a1.5 1.5 0 0 1 1.06.44l3.122 3.12A1.5 1.5 0 0 1 17 6.622V12.5a1.5 1.5 0 0 1-1.5 1.5h-1v-3.379a3 3 0 0 0-.879-2.121L10.5 5.379A3 3 0 0 0 8.379 4.5H7v-1Z" /><path d="M4.5 6A1.5 1.5 0 0 0 3 7.5v9A1.5 1.5 0 0 0 4.5 18h7a1.5 1.5 0 0 0 1.5-1.5v-5.879a1.5 1.5 0 0 0-.44-1.06L9.44 6.439A1.5 1.5 0 0 0 8.378 6H4.5Z" /></svg>`;
161→  const copiedIcon = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clip-rule="evenodd" /></svg>`;
162→
163→  document.querySelectorAll(".prose pre").forEach((pre) => {
164→    const button = document.createElement("button");
165→    button.className = "copy-button";
166→    button.innerHTML = copyIcon;
167→    button.addEventListener("click", async () => {
168→      const code = pre.querySelector("code");
169→      if (code) {
170→        await navigator.clipboard.writeText(code.textContent || "");
171→        button.classList.add("copied");
172→        button.innerHTML = copiedIcon;
173→        setTimeout(() => {
174→          button.classList.remove("copied");
175→          button.innerHTML = copyIcon;
176→        }, 2000);
177→      }
178→    });
179→    pre.appendChild(button);
180→  });
181→</script>
