/* Scroll-triggered fade-in animation */
[data-animate] {
	opacity: 0;
	transform: translateY(20px);
	transition:
		opacity 0.6s ease,
		transform 0.6s ease;
}

[data-animate].is-visible {
	opacity: 1;
	transform: translateY(0);
}

/* Reduced motion preference */
@media (prefers-reduced-motion: reduce) {
	[data-animate] {
		opacity: 1;
		transform: none;
		transition: none;
	}

